This is a clean layout. Now let me think about the proto design in detail.

**Proto design — Person:**

```proto
syntax = "proto3";
package swapi.v1;

option go_package = "github.com/example/swapi-grpc/gen/swapi/v1;swapiv1";

service PeopleService {
  rpc GetPerson(GetPersonRequest) returns (Person);
  rpc ListPeople(ListPeopleRequest) returns (ListPeopleResponse);
  rpc SearchPeople(SearchPeopleRequest) returns (ListPeopleResponse);
}

message Person {
  string id = 1;                  // slug or numeric, e.g. "1" or "luke_skywalker"
  string name = 2;
  string height = 3;              // string to preserve "unknown"
  string mass = 4;
  string hair_color = 5;
  string skin_color = 6;
  string eye_color = 7;
  string birth_year = 8;          // e.g. "19BBY"
  string gender = 9;
  string homeworld_id = 10;       // FK → PlanetsService.GetPlanet
  repeated string film_ids = 11;
  repeated string species_ids = 12;
  repeated string vehicle_ids = 13;
  repeated string starship_ids = 14;
  string created = 15;            // ISO 8601
  string edited = 16;
}

message GetPersonRequest {
  string id = 1;
}

message ListPeopleRequest {}

message ListPeopleResponse {
  repeated Person people = 1;
  int32 count = 2;                // total in response
}

message SearchPeopleRequest {
  string query = 1;               // substring match on name (case-insensitive)
}
```

**Films proto:**

```proto
syntax = "proto3";
package swapi.v1;

option go_package = "github.com/example/swapi-grpc/gen/swapi/v1;swapiv1";

service FilmsService {
  rpc GetFilm(GetFilmRequest) returns (Film);
  rpc ListFilms(ListFilmsRequest) returns (ListFilmsResponse);
  rpc SearchFilms(SearchFilmsRequest) returns (ListFilmsResponse);
}

message Film {
  string id = 1;
  string title = 2;
  int32 episode_id = 3;           // 1-6
  string opening_crawl = 4;
  string director = 5;
  string producer = 6;
  string release_date = 7;        // ISO date "1977-05-25"
  repeated string character_ids = 8;
  repeated string planet_ids = 9;
  repeated string starship_ids = 10;
  repeated string vehicle_ids = 11;
  repeated string species_ids = 12;
  string created = 13;
  string edited = 14;
}

message GetFilmRequest { string id = 1; }
message ListFilmsRequest {}
message ListFilmsResponse {
  repeated Film films = 1;
  int32 count = 2;
}
message SearchFilmsRequest { string query = 1; }
```

